#include <stdio.h>
#include <stdlib.h>

typedef struct FenwickTree {
    int* tree;
    int* arr;
    int n;
} FenwickTree;

FenwickTree* createFenwickTree(int arr[], int n) {
    FenwickTree* ft = (FenwickTree*)malloc(sizeof(FenwickTree));
    ft->n = n;
    ft->tree = (int*)calloc(n + 1, sizeof(int));
    ft->arr = (int*)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        ft->arr[i] = arr[i];
        ft->update(ft, i, arr[i]);
    }
    return ft;
}

void update(FenwickTree* ft, int idx, int delta) {
    idx++;
    while (idx <= ft->n) {
        ft->tree[idx] += delta;
        idx += idx & -idx;
    }
}

int prefixSum(FenwickTree* ft, int idx) {
    idx++;
    int total = 0;
    while (idx > 0) {
        total += ft->tree[idx];
        idx -= idx & -idx;
    }
    return total;
}

void freeFenwickTree(FenwickTree* ft) {
    free(ft->tree);
    free(ft->arr);
    free(ft);
}

int main() {
    int arr[] = {1, 3, 5, 7};
    int n = sizeof(arr) / sizeof(arr[0]);
    FenwickTree* ft = createFenwickTree(arr, n);
    printf("Prefix sum up to index 2: %d\n", prefixSum(ft, 2));
    update(ft, 1, 10 - arr[1]);
    printf("Prefix sum up to index 2 after update: %d\n", prefixSum(ft, 2));
    freeFenwickTree(ft);
    return 0;
}
// Output: Prefix sum up to index 2: 4
